import React, { useState, useEffect } from 'react';
import { salvarHistoricoNoStorage, carregarHistoricoDoStorage } from '../utils/localStorageHistorico';
import MenuLateral from '../components/MenuLateral';
import { Link, useLocation } from 'react-router-dom';

export default function EnlacesContratadosPage() {
  // ...lógica e states permanecem iguais...

  // Recupera info do cliente do localStorage (apenas para exibir)
  const [clienteInfo, setClienteInfo] = useState(null);
  const location = useLocation();
  const [clienteSelecionado, setClienteSelecionado] = useState({ cnpj: 'semcnpj' });
  useEffect(() => {
    try {
      const salvo = localStorage.getItem('clienteSelecionado');
      if (salvo) {
        const obj = JSON.parse(salvo);
        if (obj.cnpj) {
          setClienteSelecionado(obj);
          return;
        }
      }
    } catch {}
    setClienteSelecionado({ cnpj: 'semcnpj' });
  }, [location]);
  useEffect(() => {
    if (clienteSelecionado && clienteSelecionado.razaoSocial && clienteSelecionado.cnpj) {
      setClienteInfo(
        <div style={{marginBottom: 16, textAlign: 'center'}}>
          <div style={{fontWeight:700, fontSize: '1.1rem', color: '#fff'}}>{clienteSelecionado.razaoSocial}</div>
          <div style={{fontWeight:500, fontSize: '0.95rem', color: '#fff'}}>CNPJ: {clienteSelecionado.cnpj}</div>
        </div>
      );
    } else {
      setClienteInfo(null);
    }
  }, [clienteSelecionado]);

  // ...restante da lógica do componente (states, funções, etc)...

  return (
    <div style={{ display: 'flex' }}>
      <MenuLateral voltarLink={<a href="/" style={{textDecoration:'none',color:'#1976d2',fontWeight:'bold',fontSize:'1.1rem',display:'block',marginBottom:'1.5rem',marginTop:'1rem'}}>&larr; Voltar</a>} clienteInfo={clienteInfo} />
      <div style={{marginLeft:200, flex:1, minHeight:'100vh', background:'#f8f9fb', padding:'2rem'}}>
        <div style={{ flex: 1, padding: '40px 0', display: 'flex', flexDirection: 'column', alignItems: 'flex-start' }}>
          {/* Abrindo fragmento para envolver ambos os blocos */}
          <>
            <h2 style={{ color: '#1976d2', marginBottom: 24 }}>Enlaces Contratados</h2>
            {/* ...restante do conteúdo do formulário e histórico... */}
            {/* O conteúdo JSX do formulário e histórico permanece igual, apenas movido para dentro deste bloco */}
          </>
        </div>
      </div>
    </div>
  );
}
